GameMonster = class("GameMonster")

function GameMonster:ctor(monsterId, initPos, scene)
    self.monsterId = monsterId
    self.scene = scene
    local config = MonsterConfig:findById(monsterId)
    if config == nil then
        return
    end
    self.radius = config.attackedDis or 5
    self.maxHp = config.hp
    self.curHp = config.hp
    self.attack = config.attack
    self.hpQuantity = config.hpQuantity or 1
    self.returnHpTime = 0
    self.returnHpInterval = config.returnHpInterval
    self.returnHpValue = config.returnHpValue
    self.entity = nil
    self.entityId = EngineWorld:addCreatureNpc(initPos, monsterId, 0, config.actorName, function(entity)
        self.entity = entity
        entity:setScale(config.scale)
    end)
    self:syncHpInfo()
    self:updateHp()
    MonsterManager:addMonster(self)
end

function GameMonster:syncHpInfo(player)
    if player then
        GamePacketSender:SendBossHPInfo(player.rakssid, self.curHp, self.maxHp, self.hpQuantity)
        return
    end
    local players = self.scene.Players
    for _, player in pairs(players) do
        GamePacketSender:SendBossHPInfo(player.rakssid, self.curHp, self.maxHp, self.hpQuantity)
    end
end

function GameMonster:updateHp()
    if self.entity == nil then
        return
    end
    local players = self.scene.Players
    for _, player in pairs(players) do
        GamePacketSender:SendBossCurHp(player.rakssid, self.curHp, self.entityId)
    end
end

function GameMonster:attackPlayer(player)
    player:onHurt(nil, self.attack)

    if player:isDead() then
        local scene = SceneManager:getAdvancedScene(player.advancingId)
        if not scene then
            return
        end
        --player:onDie()
        scene:onBackHall(player)
        GamePacketSender:SendAdvancedResult(player.rakssid, false)
    end
end

function GameMonster:onPlayerAttack(player, skillId)
    local damage = player.property:getAttack(skillId)
    self.curHp = math.max(0, self.curHp - damage)
    self:updateHp()
    if self.curHp <= 0 then
        self:onRemove(true)
        self.scene:onGameEnd()
    end
end

function GameMonster:onTick()
    if self.curHp >= self.maxHp then
        return
    end
    if self.curHp <= 0 then
        return
    end
    local time = os.time()
    if time - self.returnHpTime >= self.returnHpInterval then
        local addHp = math.min(math.floor(self.maxHp * self.returnHpValue / 100), self.maxHp - self.curHp)
        self.curHp = self.curHp + addHp
        self:updateHp()
        self.returnHpTime = time
    end
end

function GameMonster:isDead()
    return self.curHp <= 0
end

function GameMonster:onRemove(isDie)
    if self.entityId == 0 then
        return
    end
    MonsterManager:removeMonster(self.entityId)
    if isDie then
        EngineWorld:getWorld():killCreature(self.entityId)
    else
        EngineWorld:removeEntity(self.entityId)
    end
    self.entityId = 0
    self.entity = nil
end

function GameMonster:getPosition()
    if self.entity ~= nil then
        return self.entity:getPosition()
    end
    return VectorUtil.ZERO
end

function GameMonster:getRotationYaw()
    if self.entity ~= nil then
        return self.entity.rotationYaw % 360
    end
    return 0
end

function GameMonster:getRadius()
    return self.radius
end

return GameMonster